import  React, { useState } from 'react';
import axios from 'axios';
import './Chatbot.css'; // Vom crea acest fișier CSS

// Definim tipul pentru un mesaj
interface Message {
    sender: 'user' | 'bot';
    text: string;
}

const Chatbot: React.FC = () => {
    const [isOpen, setIsOpen] = useState(false); // Starea ferestrei (deschisă/închisă)
    const [messages, setMessages] = useState<Message[]>([]); // Istoricul mesajelor
    const [input, setInput] = useState(''); // Textul din input
    const [isLoading, setIsLoading] = useState(false);

    const toggleChat = () => setIsOpen(!isOpen);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;

        const userMessage: Message = { sender: 'user', text: input };
        setMessages(prev => [...prev, userMessage]); // Adaugă mesajul userului
        setInput('');
        setIsLoading(true);

        try {
            // 1. Preluăm token-ul din localStorage
            const token = localStorage.getItem('token');

            const requestBody = {
                prompt: input
            };

            // 2. Apelăm backend-ul NOSTRU, nu API-ul Google!
            const response = await axios.post(
                'http://localhost:9090/api/chat', // Endpoint-ul din Spring Boot
                requestBody, // 2. Trimite obiectul JSON
                {
                    headers: {
                        'Authorization': `Bearer ${token}`,
                        'Content-Type': 'application/json' // 3. Schimbă Content-Type
                    }
                }
            );

            // 3. Adăugăm răspunsul bot-ului
            const botMessage: Message = { sender: 'bot', text: response.data };
            setMessages(prev => [...prev, botMessage]);

        } catch (error) {
            console.error('Eroare la chat:', error);
            const errorMessage: Message = { sender: 'bot', text: 'Oops! Ceva nu a mers bine.' };
            setMessages(prev => [...prev, errorMessage]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="chatbot-container">
            {/* Fereastra de chat */}
            {isOpen && (
                <div className="chat-window">
                    <div className="chat-header">
                        Asistent AI
                        <button onClick={toggleChat} className="chat-close-btn">&times;</button>
                    </div>
                    <div className="chat-body">
                        {messages.map((msg, index) => (
                            <div key={index} className={`chat-message ${msg.sender}`}>
                                {msg.text}
                            </div>
                        ))}
                        {isLoading && <div className="chat-message bot loading">...</div>}
                    </div>
                    <form className="chat-footer" onSubmit={handleSubmit}>
                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            placeholder="Scrie un mesaj..."
                        />
                        <button type="submit">Send</button>
                    </form>
                </div>
            )}

            {/* Butonul plutitor */}
            <button onClick={toggleChat} className="chat-toggle-button">
                {isOpen ? 'X' : '🤖'}
            </button>
        </div>
    );
};

export default Chatbot;
